export const ModuleJSON = {
  /**
   * Serializes Module to JSON.
   */
  encode: function (msg: PartialDeep<Module>): string {
    return JSON.stringify(ModuleJSON._writeMessage(msg));
  },

  /**
   * Deserializes Module from JSON.
   */
  decode: function (json: string): Module {
    return ModuleJSON._readMessage(ModuleJSON.initialize(), JSON.parse(json));
  },

  /**
   * Initializes Module with all fields set to their default value.
   */
  initialize: function (msg?: Partial<Module>): Module {
    return {
      id: "",
      name: "",
      version: "",
      manifest: "",
      state: "",
      archiveKey: "",
      functions: [],
      installedAt: protoscript.TimestampJSON.initialize(),
      updatedAt: protoscript.TimestampJSON.initialize(),
      ...msg,
    };
  },

  /**
   * @private
   */
  _writeMessage: function (msg: PartialDeep<Module>): Record<string, unknown> {
    const json: Record<string, unknown> = {};
    if (msg.id) {
      json["id"] = msg.id;
    }
    if (msg.name) {
      json["name"] = msg.name;
    }
    if (msg.version) {
      json["version"] = msg.version;
    }
    if (msg.manifest) {
      json["manifest"] = msg.manifest;
    }
    if (msg.state) {
      json["state"] = msg.state;
    }
    if (msg.archiveKey) {
      json["archiveKey"] = msg.archiveKey;
    }
    if (msg.functions?.length) {
      json["functions"] = msg.functions.map(ModuleFunctionJSON._writeMessage);
    }
    if (msg.installedAt && (msg.installedAt.seconds || msg.installedAt.nanos)) {
      json["installedAt"] = protoscript.serializeTimestamp(msg.installedAt);
    }
    if (msg.updatedAt && (msg.updatedAt.seconds || msg.updatedAt.nanos)) {
      json["updatedAt"] = protoscript.serializeTimestamp(msg.updatedAt);
    }
    return json;
  },

  /**
   * @private
   */
  _readMessage: function (msg: Module, json: any): Module {
    const _id_ = json["id"];
    if (_id_) {
      msg.id = _id_;
    }
    const _name_ = json["name"];
    if (_name_) {
      msg.name = _name_;
    }
    const _version_ = json["version"];
    if (_version_) {
      msg.version = _version_;
    }
    const _manifest_ = json["manifest"];
    if (_manifest_) {
      msg.manifest = _manifest_;
    }
    const _state_ = json["state"];
    if (_state_) {
      msg.state = _state_;
    }
    const _archiveKey_ = json["archiveKey"] ?? json["archive_key"];
    if (_archiveKey_) {
      msg.archiveKey = _archiveKey_;
    }
    const _functions_ = json["functions"];
    if (_functions_) {
      for (const item of _functions_) {
        const m = ModuleFunctionJSON.initialize();
        ModuleFunctionJSON._readMessage(m, item);
        msg.functions.push(m);
      }
    }
    const _installedAt_ = json["installedAt"] ?? json["installed_at"];
    if (_installedAt_) {
      msg.installedAt = protoscript.parseTimestamp(_installedAt_);
    }
    const _updatedAt_ = json["updatedAt"] ?? json["updated_at"];
    if (_updatedAt_) {
      msg.updatedAt = protoscript.parseTimestamp(_updatedAt_);
    }
    return msg;
  },
};

